long long solve(long long n, vector<vector<long long>> edges, long long k) {
    // Sort edges by time in ascending order
    sort(edges.begin(), edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
    });

    // Build adjacency list
    vector<vector<pair<long long, long long>>> adj(n);
    for (auto& edge : edges) {
        adj[edge[0]].push_back({edge[1], edge[2]});
        adj[edge[1]].push_back({edge[0], edge[2]});
    }

    // Union-Find data structure
    vector<long long> parent(n);
    vector<long long> rank(n, 1);

    // Find function with path compression
    auto find = [&](long long x) -> long long {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };

    // Union function with union by rank
    auto unionSets = [&](long long x, long long y) -> bool {
        long long rootX = find(x);
        long long rootY = find(y);
        if (rootX == rootY) {
            return false; // Already in the same set
        }
        if (rank[rootX] < rank[rootY]) {
            parent[rootX] = rootY;
        } else {
            parent[rootY] = rootX;
            if (rank[rootX] == rank[rootY]) {
                rank[rootX]++;
            }
        }
        return true;
    };

    // Initialize parent array
    for (long long i = 0; i < n; ++i) {
        parent[i] = i;
    }

