    long long result = 0;
    long long components = n; // Initially, each node is its own component

    for (auto& edge : edges) {
        long long u = edge[0];
        long long v = edge[1];
        long long time = edge[2];

        // Check if the edge connects two different components
        if (unionSets(u, v)) {
            components--;
        }

        // Check if we have at least k components
        if (components >= k) {
            result = time;
            break;
        }
    }

    return result;
}

